INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$LinkedIn Chrome Extension$q$, $q$One-click reveal of verified personal emails and phone numbers directly on LinkedIn and other profile pages.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Large Contact Database$q$, $q$Search across a database described as covering more than 700 million professional profiles.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Bulk Search & Lists$q$, $q$Upload lists or build saved searches to enrich many contacts at once instead of one-by-one lookups.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$ATS & CRM Integrations$q$, $q$Native integrations with Salesforce and applicant tracking systems for recruiting teams.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$API Access$q$, $q$Programmatic access to contact lookups for teams building custom workflows on the Team/API plan.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Team Management & Reporting$q$, $q$Usage dashboards, seat management, and a dedicated account manager on higher tiers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Free Daily Credits$q$, $q$A free tier grants a small daily allotment of email and phone lookups with no credit card required.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Fast, one-click lookups directly inside LinkedIn via the Chrome extension$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Separate plans for sales versus recruiting use cases, including ATS integrations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Free tier lets teams test data accuracy before buying$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Large claimed database with both email and phone coverage$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Monthly credit caps apply even on plans marketed as unlimited$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Phone number accuracy is reported as less reliable than email accuracy$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Data-sourcing methodology is not published in detail$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Annual billing is required to access the lowest advertised per-month prices$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$What is ContactOut used for?$q$, $q$ContactOut is used to find verified personal emails and phone numbers for people found on LinkedIn and other professional profiles, mainly for sales outreach and recruiting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Is there a free version of ContactOut?$q$, $q$Yes. ContactOut offers a free tier with a small daily allotment of email, phone, and personal-email lookups and no credit card required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Does ContactOut integrate with Salesforce or an ATS?$q$, $q$Yes, Salesforce and applicant tracking system integrations are available, primarily on the Recruiter and Team/API plans.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$How much does ContactOut cost?$q$, $q$Paid plans start around $49/month for sales-focused email lookups and scale up to around $199/month for recruiter plans with ATS integrations; team and enterprise pricing is custom.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Who founded ContactOut?$q$, $q$ContactOut was founded in 2015 by Rob Liu and Morny Zhang in San Francisco.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Does ContactOut work outside of LinkedIn?$q$, $q$The Chrome extension is primarily used on LinkedIn but can also surface contact data on other profile and company pages.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Outbound Sales Prospecting$q$, $q$Sales reps find verified emails and phone numbers for target buyers to fuel cold outreach and CRM enrichment.$q$, $q$SDRs and sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Passive Candidate Sourcing$q$, $q$Recruiters locate and contact passive candidates found on LinkedIn, syncing results into an ATS.$q$, $q$Recruiters and talent acquisition teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["5 email lookups/day","5 phone lookups/day","5 personal email lookups/day","Chrome extension access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Email (Sales)$q$, $q$$49/month$q$, $q$Annual ($79/month billed monthly)$q$, NULL, $q$["Up to 2,000 emails/month","Sales-focused lookups"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Email + Phone$q$, $q$$99/month$q$, $q$Annual$q$, NULL, $q$["Up to 2,000 emails/month","Up to 1,000 phone numbers/month"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Recruiter$q$, $q$$199/month$q$, $q$Annual$q$, NULL, $q$["Higher lookup caps","ATS integrations"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$Team / API$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Bulk license across 700M+ profiles","Salesforce + ATS integrations","Team management & reporting","Dedicated account manager"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ContactOut is a contact-discovery platform, best known for its Chrome extension, that reveals verified personal emails and phone numbers for professionals found on LinkedIn and other public profiles. Founded in 2015 by Rob Liu and Morny Zhang and headquartered in San Francisco, the company serves recruiters, sales teams, and marketers who need to reach people directly rather than through generic work inboxes.$q$, $q$The platform is used both for sales prospecting and for talent sourcing, and integrates with Salesforce and applicant tracking systems so contact data can flow directly into existing sales and recruiting workflows.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Chrome extension surfaces contact details in one click while browsing LinkedIn or other profile pages, drawing on a database described as covering more than 700 million professional profiles. Bulk search and list-building tools let teams enrich many contacts at once instead of looking people up one at a time.$q$, $q$Recruiter-focused plans add ATS integrations and higher lookup caps, while a Team/API plan supports Salesforce syncing, team usage reporting, and a dedicated account manager for larger organizations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ContactOut uses a freemium model. A free plan gives a small daily allotment of email and phone lookups with no credit card required. Paid plans scale from an Email plan around $49/month (billed annually) for sales use, to a combined Email + Phone plan around $99/month, to a Recruiter plan around $199/month with ATS integrations.$q$, $q$Team, API, and unlimited-user tiers are quoted directly by ContactOut's sales team; several independent reviews note that credit caps still apply on plans marketed as unlimited.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8a027b3c-fcee-43e5-9956-4c92e51917fc', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$Content Element Management$q$, $q$Structured back-end tools for building pages out of reusable content elements.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$Accessibility-first Output$q$, $q$Templates and back-end conventions oriented around producing barrier-free, WCAG-conformant websites.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$Multi-language Site Support$q$, $q$Built-in tools for running and translating multilingual websites from one installation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$Newsletter & Form Modules$q$, $q$Native newsletter sending and form-building modules without third-party plugins.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$Symfony-based Architecture$q$, $q$Built on Symfony since version 4, with Composer-based extension management via Packagist.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$Self-hosted Deployment$q$, $q$Runs on standard PHP and MySQL/MariaDB hosting, giving full control over data and infrastructure.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$Free and open source, with no software licensing fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$Strong accessibility and WCAG track record$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$Built on Symfony, familiar to PHP developers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$Active community and third-party extension marketplace$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$Requires self-hosting and ongoing PHP/MySQL server management$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$Smaller ecosystem and developer talent pool than WordPress$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$Most documentation and community activity is concentrated in German-speaking markets$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$No official managed hosting from the core project itself$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$Is Contao free?$q$, $q$Yes. Contao is free, open-source software licensed under LGPL-3.0; costs come from hosting, optional extensions, and any paid implementation support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$What was Contao previously called?$q$, $q$Contao was originally released in 2006 as TYPOLight and renamed Contao in 2010.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$What does Contao run on?$q$, $q$Contao requires PHP and a MySQL or MariaDB database, and since version 4 has been built on the Symfony framework.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$Who maintains Contao?$q$, $q$Contao is maintained by a community of core developers, the nonprofit Contao Association, and contributing agencies such as terminal42 gmbh.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$Can I self-host Contao?$q$, $q$Yes, self-hosting on a VPS, dedicated server, or partner-agency hosting is the standard deployment model.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$Does Contao support multiple languages?$q$, $q$Yes, multi-language site management is a built-in feature.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$Accessible Public-Sector Websites$q$, $q$Government and institutional sites use Contao's accessibility-oriented output to meet barrier-free web requirements.$q$, $q$Government and public-sector web teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$Multilingual Corporate Websites$q$, $q$Agencies build multilingual business websites on Contao's Symfony-based, self-hosted architecture.$q$, $q$SMBs and agencies in German-speaking Europe$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$Contao Core$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full CMS source code","Self-hosted deployment","LGPL-3.0 license","Community support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Contao is a free, open-source content management system written in PHP. It first appeared in 2006 as TYPOLight and was renamed Contao in 2010. Since version 4 (2015), it has been built on the Symfony framework and is licensed under LGPL-3.0, so it can be downloaded, self-hosted, and modified at no cost.$q$, $q$Development is coordinated by a community of core contributors, the nonprofit Contao Association, and partner agencies such as terminal42 gmbh in Lyss, Switzerland, which has maintained Contao extensions and the official Contao Manager for more than a decade.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Contao provides a full CMS toolset: page and content-element management, a newsletter module, form building, a calendar/event module, and multi-language site support. Accessibility has been a core design priority since the project's early years, and Contao is widely used by organizations that need WCAG-conformant public-facing sites.$q$, $q$Because it runs on Symfony, Contao supports Composer-based extension installation via Packagist and integrates with modern PHP development workflows, giving it a large third-party extension ecosystem.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Contao itself is free open-source software with no license fee. Costs instead come from self-hosting (server and database infrastructure), optional Contao Association membership, premium extensions sold on the Contao extension marketplace, and implementation or support services from certified Contao partner agencies.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2ffe72c4-8110-4eaf-b546-5d3899b26ca0', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Structured Content Modeling$q$, $q$Define custom content types and fields that can be reused across any channel.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$REST & GraphQL APIs$q$, $q$Content Delivery and Content Management APIs for pulling and pushing structured content programmatically.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Multi-channel Delivery$q$, $q$Publish the same content to websites, mobile apps, and other digital touchpoints from one source of truth.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Editorial Collaboration Tools$q$, $q$Comments, task management, scheduled publishing, and live multi-user collaboration.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Personalization & Experimentation$q$, $q$Ninetailed-powered A/B testing and audience segmentation, sold as an add-on Personalization product.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$AI Actions & AI Studio$q$, $q$AI-assisted content generation and workflow tooling, available on custom pricing.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$App Framework & Integrations$q$, $q$Marketplace of pre-built apps connecting Contentful to commerce, marketing, and DAM platforms.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Environments & Versioning$q$, $q$Isolated environments for staging and testing content and schema changes before publishing.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Highly flexible for multi-channel and composable architectures$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Strong developer experience with REST/GraphQL APIs and SDKs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Scales to enterprise governance needs like custom roles and SLAs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Active ecosystem of integrations and apps$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Pricing can escalate quickly with API call and space overages$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Requires front-end development resources; not a drag-and-drop site builder$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Personalization and advanced AI features are sold as separate paid add-ons$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Steeper learning curve than traditional CMS platforms for non-technical users$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$What is Contentful?$q$, $q$Contentful is a headless, API-first content management system that stores structured content and delivers it to websites, apps, and other channels via APIs.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Is Contentful free?$q$, $q$Yes, Contentful offers a free Community tier for up to 10 users with 100,000 API calls per month before paid plans are needed.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$How much does Contentful cost?$q$, $q$Contentful is free to start, with a Lite plan at €300/month and custom Enterprise pricing for larger organizations.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Who founded Contentful?$q$, $q$Contentful was founded in 2013 in Berlin, Germany by Sascha Konietzke and Paolo Negri.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Does Contentful support GraphQL?$q$, $q$Yes, alongside REST, Contentful offers a GraphQL Content Delivery API.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Is Contentful self-hosted?$q$, $q$No, Contentful is a cloud-hosted SaaS platform with no self-hosted deployment option.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Omnichannel Content Delivery$q$, $q$Enterprises manage content once and publish it across web, mobile, and other channels via APIs.$q$, $q$Enterprise marketing and engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Composable Website & App Builds$q$, $q$Development teams pair Contentful with frameworks like React or Next.js for custom front ends.$q$, $q$Digital agencies and product engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Personalized Web Experiences$q$, $q$Marketing teams run A/B tests and audience segmentation using Contentful's Personalization add-on.$q$, $q$Growth and marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["10 users","100K API calls/month","50GB CDN bandwidth","1 Starter Space"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Lite$q$, $q$€300/month$q$, $q$Monthly$q$, NULL, $q$["20 users","1M API calls/month","100GB CDN bandwidth","Comments, task management, scheduled publishing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Enterprise$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Unlimited API calls","Custom roles and locales","Dedicated support","Up to 99.99% uptime SLA"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Contentful is a headless, API-first content management system founded in 2013 in Berlin by Sascha Konietzke and Paolo Negri. It now operates from dual headquarters in Berlin and San Francisco with additional offices worldwide, and employs roughly 1,000 people.$q$, $q$Instead of coupling content to a specific website template, Contentful stores structured content and delivers it via REST and GraphQL APIs to websites, mobile apps, and other channels, making it a popular choice for enterprise and mid-market teams building composable digital experiences.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include flexible content modeling, REST and GraphQL Content Delivery and Management APIs, environments for staging content changes, and an editorial workspace with comments, task management, and scheduled publishing.$q$, $q$Beyond core CMS functionality, Contentful offers Ninetailed-powered personalization and A/B testing as an add-on product, plus emerging AI Actions and AI Studio tooling for generative content workflows, and an App Framework for integrating with commerce, marketing, and DAM systems.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Contentful's platform pricing has three tiers: a Free plan (10 users, 100K API calls/month, 50GB bandwidth), a Lite plan at €300/month (20 users, 1M API calls/month, 100GB bandwidth, plus collaboration features), and custom Enterprise pricing with unlimited API calls and dedicated support.$q$, $q$Personalization is priced separately in Start, Core, and Scale tiers based on monthly active profiles, and AI Actions/Studio pricing is quote-based. Buyer guides note usage-based overages commonly push real bills above the headline price.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
