INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$Frustration Signal Monitoring$q$, $q$Surfaces rage clicks, dead clicks, and JavaScript errors without manual recording review.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$Mobile App Analytics$q$, $q$Extends heatmap and session-level insight to native mobile app experiences.$q$, 5);
