INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$Deep behavioral insight beyond standard web analytics$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$AI-driven anomaly and frustration detection reduces manual review$q$, 1);
