INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$Covers both web and mobile app experiences$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$No public or self-serve pricing; requires a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$Enterprise-oriented cost and complexity may not suit small teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$Implementation requires tagging and SDK setup with technical resourcing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$Full feature set spans multiple licensed modules, adding cost complexity$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$What does Contentsquare do?$q$, $q$Contentsquare provides digital experience analytics, including heatmaps, session replay, and AI-powered insight into how users behave on websites and apps.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$How much does Contentsquare cost?$q$, $q$Contentsquare does not publish public pricing; it quotes enterprise contracts based on traffic volume and licensed modules.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$Who founded Contentsquare?$q$, $q$Contentsquare was founded in 2012 in Paris, France, by Jonathan Cherki.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$Does Contentsquare offer session replay?$q$, $q$Yes, full anonymized session replay is a core feature of the platform.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$Does Contentsquare have an API?$q$, $q$Yes, an API is available for exporting insights into other BI and analytics tools.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$Is Contentsquare good for mobile apps?$q$, $q$Yes, Contentsquare includes dedicated mobile app analytics alongside its web product.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$Conversion Rate Optimization$q$, $q$Growth teams use heatmaps and funnel analysis to find and fix conversion drop-off points.$q$, $q$Growth and CRO teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$UX Research & Journey Analysis$q$, $q$Product and design teams review session replays to understand real user friction.$q$, $q$Product and UX design teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$E-commerce Merchandising Insight$q$, $q$Retail teams analyze on-site behavior to optimize merchandising and product placement.$q$, $q$Digital and e-commerce teams at retail brands$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$Enterprise$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Quoted by traffic volume and licensed modules","Heatmaps, session replay, journey analysis","Optional mobile app analytics and merchandising modules"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Contentsquare is a digital experience analytics platform founded in 2012 in Paris by Jonathan Cherki. The company is headquartered in Paris with offices across North America, Europe, and Asia-Pacific, employs roughly 1,800 people, and has raised approximately $1.42 billion in funding from investors including BlackRock, KKR, and SoftBank Vision Fund 2.$q$, $q$The platform helps product, UX, marketing, and e-commerce teams understand real user behavior on websites and mobile apps, going beyond standard pageview and conversion-funnel analytics.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Contentsquare combines zone-based heatmaps, full session replay, and journey/funnel analysis with AI-powered anomaly detection that automatically flags unusual spikes in errors or conversion drops.$q$, $q$Error and frustration-signal monitoring, such as rage clicks and dead clicks, surfaces friction automatically, and the platform extends to mobile app analytics and merchandising insights for e-commerce and retail brands through acquisitions and partnerships.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Contentsquare does not publish self-service pricing. Enterprise pricing is quoted by its sales team based on traffic volume, the number of sites and apps monitored, and which modules, such as session replay or mobile analytics, a customer licenses.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('416c2613-6ccd-4b41-aea6-5f51b4411966', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
