INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$AI Writing Assistant & Image Generation$q$, $q$AI-assisted caption and post copy drafting, plus AI-generated visuals.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$Content Discovery$q$, $q$Surfaces trending articles and topics relevant to a brand's niche.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$Unified Social Inbox$q$, $q$Consolidates comments and messages from connected accounts for engagement management.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$Influencer Discovery$q$, $q$Tools for finding relevant influencers for campaigns.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$Analytics & Reporting$q$, $q$Dashboards for tracking post and campaign performance across channels.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$Approval Workflows$q$, $q$Client and team review/sign-off before posts go live, built for agency use.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$Automation Integrations$q$, $q$Native connections to Zapier, Make, n8n, and Pabbly Connect.$q$, 7);
