INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$What is ContentStudio used for?$q$, $q$ContentStudio is used to plan, create, schedule, publish, and analyze content across multiple social media networks and blogs from one dashboard.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$Does ContentStudio have a free plan?$q$, $q$No, ContentStudio offers a free trial rather than a permanent free plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$What social networks does ContentStudio support?$q$, $q$ContentStudio supports Facebook, Instagram, X, LinkedIn, TikTok, YouTube, Pinterest, Threads, Google Business Profile, and blog platforms like WordPress and Shopify.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$Does ContentStudio include AI content tools?$q$, $q$Yes, it includes an AI writing assistant for captions and post copy plus AI image generation.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$How much does ContentStudio cost?$q$, $q$Plans start around $19/month for a single user and scale to around $99/month for unlimited users on the Agency plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$Is ContentStudio good for agencies?$q$, $q$Yes, its Agency Unlimited plan and client approval workflows are designed for agencies managing multiple accounts.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$Agency Social Media Management$q$, $q$Agencies manage multiple client accounts with approval workflows and unlimited users.$q$, $q$Digital marketing agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$Content Marketing Scheduling$q$, $q$In-house marketing teams plan and publish content across social and blog channels.$q$, $q$In-house marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$Multi-brand Publishing$q$, $q$Growing businesses manage several social profiles from a single dashboard.$q$, $q$Businesses managing multiple social profiles$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$Standard$q$, $q$$19/month$q$, $q$Monthly/Annual$q$, NULL, $q$["1 user","5 social accounts"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$Advanced$q$, $q$$49/month$q$, $q$Monthly/Annual$q$, NULL, $q$["1 user","25 social accounts"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$Agency Unlimited$q$, $q$$99/month$q$, $q$Monthly/Annual$q$, NULL, $q$["Unlimited users","50 social accounts"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ContentStudio is a social media and content marketing management platform founded in 2017 by Waqar Azeem, with teams based in Lahore and Islamabad, Pakistan, and US registration in Claymont, Delaware. It targets marketers, agencies, and small-to-midsize businesses managing multiple social accounts.$q$, $q$The platform competes with tools like Hootsuite, Buffer, and Sprout Social, differentiating with built-in AI content creation, content discovery, and agency-oriented approval workflows.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ContentStudio provides a unified content calendar and scheduler across Facebook, Instagram, X, LinkedIn, TikTok, YouTube, Pinterest, Threads, and Google Business Profile, plus blog publishing to WordPress, Medium, and Shopify.$q$, $q$The platform includes an AI writing assistant and AI image generation, content discovery for trending topics, a unified social inbox, influencer discovery, analytics and reporting, and approval workflows built for agencies managing multiple clients.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ContentStudio has no permanent free plan, only a free trial. The Standard plan starts around $19/month (1 user, 5 social accounts), the Advanced plan is around $49/month (1 user, 25 accounts), and the Agency Unlimited plan is around $99/month (unlimited users, 50 accounts).$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('781eb9ec-2374-430e-a835-e05378d167bf', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
