INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$Matrix Protocol Federation$q$, $q$Full server-side implementation of the Matrix specification for federated, decentralized chat.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$Rust-based Low Resource Usage$q$, $q$Built in Rust to run efficiently on modest hardware compared to Python-based homeservers like Synapse.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$Appservice Bridge Support$q$, $q$Supports bridging to external chat platforms via Matrix appservices.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$Multiple Deployment Methods$q$, $q$Docker, Kubernetes, NixOS, and traditional binary installation are all documented.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$Frequent Releases$q$, $q$New releases are cut roughly every one to two weeks.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$Migration Tooling$q$, $q$Documentation and tooling for migrating from existing conduwuit installations.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$Public Demo Homeservers$q$, $q$Community-run instances like continuwuity.rocks let users try Matrix without self-hosting first.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$Free, open-source, and self-hosted with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$Lightweight enough to run on modest hardware$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$Actively maintained with frequent releases, unlike the archived conduwuit$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$Full interoperability with the wider Matrix and Element ecosystem$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$Requires self-hosting expertise in server administration and the Rust ecosystem$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$Young project, forked in 2025, with a shorter track record than Synapse$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$No official commercial support or SLA$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$Migration from some other homeservers, such as the original Conduit or Grapevine, is not supported$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$What is Continuwuity?$q$, $q$Continuwuity is a free, open-source Matrix homeserver written in Rust, forked from conduwuit as a community-maintained continuation of the project.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$Is Continuwuity free?$q$, $q$Yes, Continuwuity is free and open source under the Apache License 2.0.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$What language is Continuwuity written in?$q$, $q$Continuwuity is written primarily in Rust.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$Can I self-host Continuwuity?$q$, $q$Yes, self-hosting is the primary way to run Continuwuity, with Docker, Kubernetes, NixOS, and binary installation options documented.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$Is Continuwuity compatible with Matrix clients like Element?$q$, $q$Yes, Continuwuity implements the Matrix protocol and federates with the wider Matrix network, including Element clients.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$Why was Continuwuity created?$q$, $q$Continuwuity was created after the original conduwuit project's maintainer stepped back and the project was archived, so community contributors forked it to keep it maintained.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$Self-hosted Team or Community Chat$q$, $q$Organizations and communities run their own federated chat server instead of relying on a centralized provider.$q$, $q$Privacy-focused communities and organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$Lightweight Homelab Matrix Server$q$, $q$Self-hosters run Continuwuity on a small VPS or Raspberry Pi as part of a personal homelab setup.$q$, $q$Self-hosting enthusiasts and system administrators$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code","Apache-2.0 license","Community support via Matrix chat","Public issue tracker"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Continuwuity is a free, open-source Matrix homeserver written in Rust, forked in April 2025 as a community continuation of conduwuit after that project's original maintainer stepped back and it was eventually archived. It is maintained by a group of Matrix enthusiasts, developers, and system administrators, including former conduwuit contributors.$q$, $q$The project implements the Matrix protocol server-side under the Apache License 2.0, allowing anyone to self-host a chat server that federates with the wider Matrix network, including Element and other Matrix clients.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Continuwuity is designed to be lightweight and efficient, running on modest hardware such as a small VPS or Raspberry Pi, in contrast to the heavier resource footprint of Synapse, the original Matrix homeserver. It supports appservice bridges for connecting to external platforms and ships new releases roughly every one to two weeks.$q$, $q$Deployment options include Docker, Kubernetes, NixOS packages, and traditional binary installation, with documentation covering migration from conduwuit installs. Public demo homeservers such as continuwuity.rocks let people try the software before self-hosting.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Continuwuity is free, open-source software with no licensing cost. As a self-hosted project, the only expenses are server infrastructure and administration time; support comes from community Matrix channels and public issue trackers rather than a paid contract.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('35d633ed-e78a-443f-ae86-ab29e7bc10d2', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$Template-based Contract Drafting$q$, $q$Draft contracts from a library of customizable templates.$q$, 0);
