INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$AI Contract Assistant & Data Extraction$q$, $q$AI-assisted drafting help plus automatic extraction of key terms from uploaded documents.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$Obligation & Renewal Tracking$q$, $q$Track key dates and obligations so teams do not miss contract renewals or expirations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$Approval & Automation Workflows$q$, $q$Automations and dynamic templates streamline recurring contract processes on higher tiers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$Reporting & CSV Export$q$, $q$Export contract data and generate reports for compliance and audit purposes.$q$, 6);
