INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$AI-assisted drafting and data extraction speed up contract creation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$Now backed by Scrive's signature and identity-verification infrastructure$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$Named pricing tiers make direct cost comparison harder than flat per-seat pricing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$Entry tiers cap users, templates, and annual contract volume$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$Publicly reported pricing details vary across sources and may be outdated post-acquisition$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$Deeper integrations and customization require the custom/enterprise tier$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$What is Contractbook?$q$, $q$Contractbook is a contract lifecycle management platform for drafting, e-signing, storing, and automating contracts.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$Is Contractbook free?$q$, $q$Contractbook offers a 14-day free trial but does not have a permanent free plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$Who owns Contractbook?$q$, $q$Contractbook has been part of Scrive, a Nordic e-signature company, since it was acquired in June 2025.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$Does Contractbook support e-signatures?$q$, $q$Yes, including support for Nordic digital identity schemes such as BankID and NemID/MitID.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$Where is Contractbook based?$q$, $q$Contractbook is headquartered in Copenhagen, Denmark.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$Does Contractbook offer an API?$q$, $q$Yes, API integrations are available, particularly on the higher and custom pricing tiers.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$SMB Contract Management$q$, $q$Small businesses move contract creation and storage off email and paper into one platform.$q$, $q$Small business owners and operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$Sales & HR Contract Automation$q$, $q$Teams automate recurring agreements like sales contracts or employment paperwork with templates and tracking.$q$, $q$Sales operations and HR teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$Essential$q$, $q$Contact sales for current pricing$q$, $q$Annual$q$, NULL, $q$["1 user","Up to ~100 signed contracts/year","5 templates","AI contract assistant","Unlimited e-signatures"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$Centralize$q$, $q$Contact sales for current pricing$q$, $q$Annual$q$, NULL, $q$["Up to 5 users","~350 signed contracts/year","15 templates","AI-powered data extraction","Dedicated Success Manager"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$Accelerate$q$, $q$Contact sales for current pricing$q$, $q$Annual$q$, NULL, $q$["Up to 10 users","~500 signed contracts/year","25 templates","Automations","Dynamic templates","White-glove onboarding"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$Custom / Enterprise$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Technical customization","API integrations","Dedicated implementation consultancy"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Contractbook is a contract lifecycle management platform founded in 2017 in Copenhagen, Denmark. It has raised venture funding from investors including Tiger Global and Bessemer Venture Partners and reports serving more than 250,000 users across 85+ countries.$q$, $q$In June 2025, Contractbook was acquired by Scrive, a Nordic e-signature company, and now operates as part of the Scrive group, pairing Contractbook's contract-lifecycle tooling with Scrive's e-signature and digital identity infrastructure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Contractbook covers the full contract lifecycle: drafting from customizable templates, collaborative redlining, legally binding e-signatures (including Nordic digital ID schemes like BankID and NemID/MitID), a searchable contract repository, and obligation and renewal-date tracking.$q$, $q$AI-assisted features include a contract drafting assistant and AI-powered data extraction that pulls key terms and metadata from uploaded contract documents, alongside CSV export and reporting for compliance and audit needs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Contractbook uses named, tiered subscription plans (Essential, Centralize, Accelerate, and a custom Enterprise tier) that scale by user count, template library size, and annual signed-contract volume rather than simple per-seat pricing. A 14-day free trial is available, and annual billing can save up to 25% versus monthly billing. Exact current prices should be confirmed with sales, since figures vary across sources and pricing has evolved since the 2025 Scrive acquisition.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d2ccb15e-37d0-481d-a412-ddf5ab66d3dc', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
