INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$Secure Encrypted Storage$q$, $q$Centralized, encrypted cloud storage for contracts and related documents.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$Built-in Electronic Signatures$q$, $q$Draft and execute agreements without needing a separate e-signature tool.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$Customizable Reporting & Dashboards$q$, $q$Track contract status, renewal dates, and compliance obligations.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$Renewal & Obligation Alerts$q$, $q$Automated tracking of key dates so teams do not miss renewals or deadlines.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$Granular Permissions & Audit Trails$q$, $q$Control access at a granular level and maintain a full audit history.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$Flat-rate Unlimited-user Pricing$q$, $q$One flat monthly price covers unlimited users rather than per-seat billing.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$Expanded API & Integrations$q$, $q$Broader integration capabilities following the Onit acquisition.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$Flat-rate pricing removes per-seat cost scaling for large teams$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$AI auto-tagging speeds up organizing an existing contract backlog$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$Built-in e-signatures avoid needing a separate tool$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$No extra fees for implementation, training, or migration$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$Entry price of around $600/month is a meaningful commitment for very small teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$Detailed pricing above the entry tier is not fully public$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$Less configurable than dedicated enterprise CLM platforms for complex workflows$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$No dedicated native mobile apps; access is web-only$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$What is ContractWorks?$q$, $q$ContractWorks is a contract lifecycle management platform, now sold as an Onit product, offering AI-driven extraction, secure storage, and e-signatures.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$How much does ContractWorks cost?$q$, $q$ContractWorks starts at around $600 per month with unlimited users included.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$Does ContractWorks include e-signatures?$q$, $q$Yes, built-in electronic signatures are included without needing a separate tool.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$Is ContractWorks the same as Onit?$q$, $q$ContractWorks is a product owned and marketed by Onit, a legal operations software company; the two are increasingly unified under the Onit brand.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$Does ContractWorks use AI?$q$, $q$Yes, it uses AI to extract and auto-tag key contract data such as dates and obligations on upload.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$Who founded ContractWorks?$q$, $q$ContractWorks was founded in 2013 in Houston, Texas, and was later acquired by Onit.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$Contract Backlog Organization$q$, $q$Legal teams use AI extraction to quickly organize and tag an existing library of contracts.$q$, $q$Legal and compliance teams digitizing existing contracts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$Company-wide Contract Visibility$q$, $q$Organizations give many employees access to contract data under flat-rate, unlimited-user pricing.$q$, $q$Mid-sized companies wanting broad contract access$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$Standard$q$, $q$$600/month$q$, $q$Monthly/Annual$q$, NULL, $q$["Unlimited users","Secure encrypted storage","AI extraction & auto-tagging","Built-in e-signatures","Dedicated account manager","No implementation or training fees"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$Enterprise$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Expanded API access","Advanced integrations via Onit","Custom reporting"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ContractWorks is a contract lifecycle management platform founded in 2013 in Houston, Texas. It was later acquired by Onit, a legal operations software company headquartered in Austin, Texas, and now operates as "ContractWorks, an Onit product," unified increasingly under the Onit brand.$q$, $q$The platform is positioned as an easier-to-adopt alternative to complex enterprise CLM suites, aimed at legal, finance, and procurement teams that want centralized contract storage and tracking without a long implementation project.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include secure encrypted document storage, AI-driven contract data extraction and auto-tagging of key fields like expiration dates and obligations, built-in electronic signatures, customizable reporting dashboards, and granular user permissions with audit trails.$q$, $q$Following the Onit acquisition, ContractWorks has expanded its API and integration capabilities, allowing it to connect with other systems in a broader legal-operations or procurement tech stack.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('19ec34e7-46e8-4c4e-851d-20bbb23e224e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ContractWorks uses flat-rate, unlimited-user pricing rather than per-seat billing, starting at around $600 per month, which includes a dedicated account manager and no separate implementation, training, or migration fees. Pricing above the entry tier is quoted directly by the ContractWorks/Onit sales team.$q$]::text[], 2);
