-- Enrichment marathon batch: ContactOut, Contao, Contentful, Contentsquare, ContentStudio, Continuwuity, Contractbook, ContractWorks

-- ── ContactOut ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$ContactOut is a Chrome extension and web platform that finds verified personal emails and phone numbers from LinkedIn profiles for recruiters and sales teams.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $49/month)$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$~90 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, US$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$ContactOut: Pricing, Features, and Alternatives 2026$q$, seo_title),
  seo_meta_description = COALESCE($q$ContactOut finds verified emails and phone numbers from LinkedIn profiles. See 2026 pricing, key features, pros and cons, and how it compares to rivals.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ContactOut is a contact-data and email-finding platform founded in 2015 by Rob Liu and Morny Zhang, headquartered in San Francisco, California. The company employs roughly 90 people and serves more than 1.4 million recruiters, sales representatives, and marketers, including staff at Fortune 500 companies. Its core product is a Chrome browser extension plus a web dashboard and API that surface personal (non-work) email addresses and mobile phone numbers for professionals found on LinkedIn, GitHub, and other public profiles, claiming coverage for roughly 75% of the people users search for, drawn from a database described as covering more than 700 million profiles. ContactOut is positioned against competitors such as Apollo.io, Lusha, Hunter.io, RocketReach, and SignalHire in the sales-intelligence and recruiting-tech category. The product line splits into two main use cases: sales prospecting (finding buyer contact details to fuel outbound outreach and CRM enrichment) and recruiting (sourcing passive candidates and enriching applicant records for applicant tracking systems). ContactOut integrates with Salesforce and major ATS platforms, and offers bulk search, list building, and data export tools alongside its per-profile lookup extension. Pricing follows a freemium model: a free tier provides a small daily allotment of email, phone, and personal-email lookups (reported as five of each per day); paid plans include an Email plan for sales users (around $49 per month billed annually, or roughly $79 billed monthly, capped at about 2,000 email credits per month), a combined Email + Phone plan (around $99 per month annually, with roughly 2,000 email and 1,000 phone credits), and a Recruiter plan (around $199 per month annually) aimed at talent teams that need ATS integrations and higher credit caps. Team and enterprise pricing, including an API/bulk-license option and a reported unlimited-sales-user tier near $299 per month, is quoted directly by ContactOut's sales team, and multiple independent reviews note that "unlimited" marketing on higher tiers is subject to fair-use credit caps not always shown on the public pricing page. ContactOut does not publish its underlying data-sourcing methodology in detail, and third-party reviewers highlight variable data accuracy for phone numbers versus emails as a common trade-off with this category of contact-enrichment tool. The product is delivered as a SaaS web application and a Chrome extension; there is no self-hosted or open-source version. For teams evaluating ContactOut, the main decision points are: daily and monthly credit caps versus actual outreach volume needed, whether Salesforce or ATS integration is required, and how ContactOut's per-credit economics compare to competitors like Apollo or Lusha for the specific mix of email versus direct-dial phone lookups a team needs.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8a027b3c-fcee-43e5-9956-4c92e51917fc';

