-- ── Contao ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Contao is a free, open-source PHP content management system for building accessible, secure websites, self-hosted and maintained by a community and the Contao Association.$q$, short_description),
  pricing_model = COALESCE($q$Free/Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Lyss, Switzerland (Contao Association / terminal42 gmbh)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Contao CMS: Features, Pricing, and Overview$q$, seo_title),
  seo_meta_description = COALESCE($q$Contao is a free, open-source PHP CMS for accessible, secure websites. Learn about its history, features, self-hosting requirements, and community support.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Contao is a free, open-source content management system written in PHP, originally released in 2006 under the name TYPOLight before being renamed Contao in 2010 to avoid confusion with the similarly named TYPO3 CMS. Since version 4, released in 2015, Contao has been built on the Symfony PHP framework, and the project is licensed under the LGPL-3.0 open-source license, meaning it can be downloaded, self-hosted, and modified free of charge. Contao is maintained by a community of core developers coordinated in large part through the nonprofit Contao Association, which anyone can join as a paying member to help fund ongoing development, and by contributing agencies such as terminal42 gmbh, based in Lyss, Switzerland, one of the most active long-term contributors to the Contao core and its official Contao Manager installation tool. Contao ships as a full CMS: it includes a structured back end for managing pages, articles, and content elements; a built-in newsletter module; form generation; a calendar and event-listing module; multi-language site support; and accessibility features that reflect the project's original focus on producing barrier-free websites, a priority since Contao has historically been used by German public-sector and accessibility-focused organizations. Because it runs on Symfony, Contao supports modern PHP development practices, Composer-based dependency management via Packagist, and a large extension ecosystem contributed by third-party developers and agencies. Contao requires a standard PHP and MySQL/MariaDB hosting stack and is typically self-hosted on a VPS, dedicated server, or specialized Contao hosting offered by partner agencies, rather than delivered as a managed SaaS product. There is no proprietary paid tier of Contao itself: the core software is free to download and use, and the project's revenue model instead centers on the Contao Association's membership fees, paid extensions and themes sold by third-party developers on the Contao extension marketplace, and paid implementation, hosting, and support services offered by certified Contao partner agencies such as terminal42. This makes Contao's total cost of ownership dependent on hosting choice, developer or agency fees, and any premium extensions selected, rather than a fixed software subscription. Contao competes in the open-source CMS space against WordPress, TYPO3, Drupal, and ProcessWire, and is most commonly chosen by organizations that want a lightweight but full-featured, self-hosted, Symfony-based CMS with strong out-of-the-box accessibility and multilingual support, particularly in the German-speaking European market where it originated and remains most widely adopted. Governance is community-driven rather than controlled by a single commercial vendor, with release planning, security patches, and roadmap discussion happening publicly on GitHub and at Contao core developer meetups.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2ffe72c4-8110-4eaf-b546-5d3899b26ca0';

