-- ── Contentsquare ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Contentsquare offers heatmaps, session replay, and AI-driven experience analytics for enterprise UX, product, and marketing teams optimizing websites and apps.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (custom/enterprise pricing)$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$~1,800 employees$q$, company_size),
  headquarters = COALESCE($q$Paris, France$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Contentsquare: Digital Experience Analytics Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Contentsquare offers heatmaps, session replay, and AI experience analytics for enterprise UX teams. See key features, pricing model, and pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Contentsquare is a digital experience analytics platform founded in 2012 in Paris, France, by Jonathan Cherki, who started the company as a student project before building it into one of the largest independent experience-analytics vendors. Headquartered in Paris with offices across North America, Europe, and Asia-Pacific, Contentsquare employs approximately 1,800 people as of 2026 and has raised roughly $1.42 billion in total funding across multiple rounds, including a $500 million Series E in 2021 and a $600 million Series F in 2022, reaching a reported $5.6 billion valuation; investors include BlackRock, KKR, SoftBank Vision Fund 2, Highland Europe, and Eurazeo. The platform is built for product, UX, marketing, and e-commerce teams that need to understand how real users behave on websites and mobile apps beyond what standard web analytics such as pageviews and conversion funnels can show. Its core capabilities include zone-based heatmaps that visualize where users click, scroll, and hover; full session replay so teams can watch anonymized recordings of individual user journeys; journey and funnel analysis to find drop-off points; AI-powered anomaly detection that automatically flags unusual spikes in errors, rage clicks, or conversion drops; and error and frustration-signal monitoring, such as rage clicks, dead clicks, and JavaScript errors, that surfaces friction without requiring teams to manually review recordings. Contentsquare has grown through acquisitions, including session-replay and product-analytics companies, to broaden its platform beyond web analytics into a fuller experience-intelligence suite covering web, mobile app, and, through partnerships, voice-of-customer and merchandising data for retail and e-commerce brands. The product is delivered as an enterprise SaaS platform with a JavaScript/SDK-based tag deployed on customer sites and apps, plus a dashboard, an API for exporting insights into BI tools, and integrations with major tag managers, CDPs, and marketing platforms such as Google Analytics, Adobe Experience Cloud, Salesforce, and Optimizely. Contentsquare does not publish self-service or per-seat pricing publicly; enterprise pricing is quoted individually by its sales team based on traffic volume, number of sites and apps monitored, and which modules, such as session replay, mobile app analytics, or merchandising, a customer licenses, which is typical for large-scale experience analytics vendors given the data volumes involved. This makes Contentsquare best suited to mid-market and enterprise organizations with dedicated UX, conversion rate optimization, or digital product teams rather than solo site owners or small businesses, and it primarily competes with platforms such as FullStory, Hotjar, Microsoft Clarity, Quantum Metric, and Adobe Analytics and Target in the behavioral and experience analytics category.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '416c2613-6ccd-4b41-aea6-5f51b4411966';

