-- ── Continuwuity ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Continuwuity is a free, open-source Rust Matrix homeserver forked from conduwuit for self-hosted, federated chat. See features and deployment options.$q$, short_description),
  pricing_model = COALESCE($q$Free/Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2025, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Continuwuity: Open-Source Matrix Homeserver in Rust$q$, seo_title),
  seo_meta_description = COALESCE($q$Continuwuity is a free, open-source Rust Matrix homeserver forked from conduwuit. Learn about self-hosting, key features, and how it fits the Matrix ecosystem.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Continuwuity is a free and open-source Matrix protocol homeserver written in Rust, created in April 2025 as a community-driven continuation of conduwuit, a lightweight Rust rewrite of the original Conduit homeserver. Continuwuity was started after conduwuit's original maintainer stepped back and the project was eventually archived, formally archived in January 2026, prompting a group of Matrix enthusiasts, developers, and system administrators, including some former conduwuit contributors alongside new developers, to fork the codebase, keep it actively maintained, fix outstanding bugs, and add features the community wanted rather than let a widely-used lightweight homeserver go unmaintained. The project is released under the Apache License 2.0 and is hosted primarily on the developers' own Forgejo instance and mirrored to GitHub and Codeberg, reflecting the broader Matrix and self-hosting community's preference for federated, non-corporate infrastructure. Continuwuity implements the Matrix specification server-side, meaning it lets an individual or organization run their own chat homeserver that federates with the wider Matrix network, including Element and other Matrix clients and public rooms hosted on matrix.org and elsewhere, rather than depending on a centralized chat provider. Compared to Synapse, the original and most feature-complete Matrix homeserver written in Python, Continuwuity, like conduwuit before it, targets significantly lower resource usage and simpler operations, making it viable to self-host on modest hardware such as a small VPS, a Raspberry Pi, or a home server, which is its primary differentiator and audience: privacy-conscious individuals, small communities, and organizations that want to self-host chat infrastructure without Synapse's heavier PostgreSQL and Python-stack resource footprint. The project ships releases roughly every one to two weeks and documents multiple deployment paths, including Docker, Kubernetes, NixOS packages, and traditional binary installation, with configuration and migration guides for administrators moving from conduwuit or other homeservers, noting that direct database migration from some homeservers, such as the original Conduit or Grapevine, is not supported due to storage-format incompatibilities. Continuwuity also operates or partners on public demo and community Matrix homeservers, such as continuwuity.rocks and federated.nexus, so prospective administrators and end users can try the software or join a hosted instance without deploying their own server first. As a community project rather than a commercial product, Continuwuity has no pricing plans, company headquarters, or employee count; its cost is the server infrastructure and administration time required to self-host it, and support is provided through community channels, such as Matrix chat rooms, and public issue trackers rather than a paid support contract. It competes with and complements other Matrix homeserver implementations, including Synapse, Dendrite, and other Conduit-family forks, as part of the broader decentralized and federated chat ecosystem that also includes protocols like XMPP and ActivityPub-based platforms.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '35d633ed-e78a-443f-ae86-ab29e7bc10d2';

