-- ── Contractbook ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Contractbook is a Copenhagen-based contract lifecycle management platform for drafting, e-signing, storing, and automating contracts, now part of Scrive.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Copenhagen, Denmark$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Danish$q$]::text[],
  seo_title = COALESCE($q$Contractbook: Contract Management Pricing & Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Contractbook offers contract drafting, e-signing, and lifecycle automation for growing businesses. See key features, pricing tiers, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Contractbook is a contract lifecycle management platform founded in 2017 in Copenhagen, Denmark, where the company remains headquartered. It raised venture funding from investors including Tiger Global, Bessemer Venture Partners, and Gradient Ventures, and reports serving more than 250,000 users across more than 85 countries, primarily small and mid-sized businesses that want to move contract creation, signing, storage, and management off email and paper without adopting a heavyweight enterprise CLM suite. In June 2025, Contractbook was acquired by Scrive, a Nordic e-signature and digital contract company, and now operates as part of the Scrive group, combining Contractbook's contract-lifecycle and automation tooling with Scrive's e-signature and identity-verification infrastructure, including support for Nordic digital ID schemes such as BankID and NemID/MitID. The platform's core workflow covers the full contract lifecycle: drafting contracts from a library of customizable templates, collaborating on and redlining drafts with counterparties, collecting legally binding electronic signatures, storing signed and unsigned contracts in a searchable repository, and tracking key dates, obligations, and renewal deadlines so teams do not miss contract expirations. Contractbook also offers AI-assisted features, including an AI contract assistant for drafting help and AI-powered data extraction that can pull key terms and metadata out of uploaded, non-native contract documents, plus CSV export and reporting for compliance and audit purposes. Pricing is structured as tiered, named subscription plans rather than simple per-seat pricing: entry-level plans are aimed at solo operators or very small teams with a limited number of users, templates, and signed contracts per year, while mid- and upper-tier plans aimed at growing and scaling companies raise the user count, template library size, and annual signed-contract volume, and add automation, dynamic templates, user provisioning, a dedicated Customer Success Manager, and white-glove onboarding. A custom or enterprise tier is available for organizations that need deeper technical customization, API integrations, and dedicated implementation consultancy; Contractbook's marketing states customers can save up to 25% by choosing annual billing over monthly billing, and a 14-day free trial with full feature access and no credit card required is offered for prospective customers to evaluate the platform. Because pricing is presented as bundled named tiers rather than transparent flat per-user rates and has changed following the Scrive acquisition, prospective buyers should confirm current figures directly with Contractbook or Scrive sales rather than relying on older third-party pricing roundups. Contractbook competes with other contract lifecycle and e-signature platforms such as PandaDoc, DocuSign CLM, Ironclad, and Concord, differentiating primarily on its all-in-one drafting-to-signature-to-repository workflow, its strong footprint in the Nordic and broader European market, and its now-combined offering with Scrive's e-signature and identity-verification technology.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd2ccb15e-37d0-481d-a412-ddf5ab66d3dc';

