-- ── ContractWorks ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$ContractWorks, an Onit product, is a contract management platform offering AI-driven extraction, secure storage, and e-signatures at a flat monthly rate for unlimited users.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (flat-rate, unlimited users)$q$, pricing_model),
  starting_price = COALESCE($q$$600/month$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Houston, Texas, US (now part of Onit, headquartered in Austin, Texas)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$ContractWorks: Contract Management Pricing & Features$q$, seo_title),
  seo_meta_description = COALESCE($q$ContractWorks, an Onit product, offers AI-powered contract management with flat-rate pricing for unlimited users. See features, plans, pros, and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ContractWorks is a contract lifecycle management platform founded in 2013 and originally headquartered in Houston, Texas. The company was acquired by Onit, a legal operations and enterprise legal management software provider headquartered in Austin, Texas, and ContractWorks now operates as an Onit product, with the two brands increasingly unified under Onit's platform and marketing; customer-facing materials now typically refer to it as "ContractWorks, an Onit product." ContractWorks is positioned as a scalable, easier-to-adopt alternative to complex enterprise CLM suites, aimed at legal, finance, procurement, and operations teams that need centralized contract storage, tracking, and reporting without a long implementation cycle. Its core capabilities include secure, encrypted cloud storage for contracts and related documents; AI-driven contract data extraction and auto-tagging that automatically identifies and tags key fields such as expiration dates, obligations, parties, and governing terms upon upload, reducing manual data entry; built-in electronic signatures for drafting and executing agreements without a separate e-signature tool; customizable reporting and dashboards for tracking contract status, renewal dates, and compliance obligations; granular user permissions and audit trails; and expanded API and integration capabilities following the Onit acquisition, allowing ContractWorks to connect with other systems in a broader legal-ops or procurement tech stack. A distinguishing feature of ContractWorks' commercial model is flat-rate, unlimited-user pricing: rather than charging per seat, ContractWorks publishes a starting price of around $600 per month that includes unlimited users, a dedicated account manager, and no separate implementation, training, or data-migration fees, a structure aimed at organizations that want many employees, not just a small legal team, to have visibility into contracts without per-seat cost scaling. Exact plan tiers above the entry price, such as for higher storage, more advanced AI extraction, or additional integrations, are quoted directly by ContractWorks and Onit sales rather than published in full detail. ContractWorks competes with other mid-market and enterprise CLM tools such as Ironclad, Concord, PandaDoc, and ContractPodAi, as well as its own corporate sibling products within Onit's broader legal-ops suite, and is most often selected by legal and compliance teams at mid-sized companies that want AI-assisted organization of an existing contract backlog plus straightforward e-signature and reporting, without adopting a full enterprise-grade CLM implementation project. The product is delivered as a cloud-based SaaS web application; there is no self-hosted or open-source deployment option, and access is provided through a responsive web interface rather than dedicated native mobile apps.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '19ec34e7-46e8-4c4e-851d-20bbb23e224e';

